def min_geq(n_str, allowed):
    allowed = sorted(allowed)
    n = len(n_str)

    def solve(digits, pos, tight):
        # returns the number as string or None
        if pos == len(digits):
            return ""

        lo = int(digits[pos]) if tight else 0
        for d in allowed:
            if d < lo:
                continue
            new_tight = tight and (d == int(digits[pos]))
            rest = solve(digits, pos + 1, new_tight)
            if rest is not None:
                fill = min(allowed) if not new_tight else None
                if new_tight:
                    if rest is not None:
                        return str(d) + rest
                else:
                    # fill remaining with min allowed
                    remaining = len(digits) - pos - 1
                    return str(d) + str(min(allowed)) * remaining
        return None

    # Try same length
    digits = [int(c) for c in n_str]
    # Need first digit != 0
    result = solve(digits, 0, True)
    if result and result[0] != '0':
        return int(result)

    # Try length+1
    min_d = min(d for d in allowed if d > 0)
    return int(str(min_d) + str(min(allowed)) * n)

